const { Alert, Card, Col, Row, Statistic, Table, Tag, Typography, Space } = ctx.libs.antd;
const t = ctx.t || ((value) => value);
function unwrapDigest(response) {
  let data = response;
  for (let i = 0; i < 5; i += 1) {
    if (!data || typeof data !== 'object' || Array.isArray(data) || data.summary || !('data' in data)) break;
    data = data.data;
  }
  return {
    summary: data && data.summary ? data.summary : {},
    sections: {
      orderNow: Array.isArray(data && data.sections && data.sections.orderNow) ? data.sections.orderNow : [],
      suppliersToContactFirst: Array.isArray(data && data.sections && data.sections.suppliersToContactFirst) ? data.sections.suppliersToContactFirst : [],
      supplierActionItems: Array.isArray(data && data.sections && data.sections.supplierActionItems) ? data.sections.supplierActionItems : [],
      staleLeadTimes: Array.isArray(data && data.sections && data.sections.staleLeadTimes) ? data.sections.staleLeadTimes : [],
    },
  };
}
function colorForAction(value) {
  if (value === 'overdue') return 'red';
  if (value === 'order_today') return 'volcano';
  if (value === 'missing_lead_time') return 'gold';
  if (value === 'order_soon') return 'orange';
  if (value === 'already_ordered') return 'green';
  return 'default';
}
function colorForTier(value) {
  if (value === 'A') return 'green';
  if (value === 'B') return 'gold';
  if (value === 'C') return 'red';
  return 'default';
}
function colorForFreshness(value) {
  if (value === 'fresh') return 'green';
  if (value === 'stale') return 'orange';
  if (value === 'missing') return 'red';
  return 'default';
}
function groupDigits(value) {
  return String(value).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}
function money(value) {
  const parsed = Number(value || 0);
  const rounded = Math.round(parsed);
  return '$' + groupDigits(rounded);
}
function number(value) {
  const parsed = Number(value || 0);
  return isFinite(parsed) ? groupDigits(parsed) : '—';
}
let digest;
try {
  const response = await ctx.request({
    url: 'ecobaseInventoryPlanning:digestPreview',
    method: 'post',
    data: { leadTimeFreshnessDays: 60, orderSoonWindowDays: 14, limit: 150 },
    skipNotify: true,
  });
  digest = unwrapDigest(response);
} catch (error) {
  ctx.render(<Alert type="error" showIcon message={t('Could not load digital digest preview')} description={String(error && error.message ? error.message : error)} />);
  return;
}
const orderColumns = [
  { title: t('Action'), dataIndex: 'actionStatus', render: (value) => <Tag color={colorForAction(value)}>{t(value || 'unknown')}</Tag> },
  { title: t('Tier'), dataIndex: 'tier', render: (value) => <Tag color={colorForTier(value)}>{value || '—'}</Tag> },
  { title: t('Company'), dataIndex: 'company' },
  { title: t('ASIN'), dataIndex: 'asin' },
  { title: t('Supplier next action'), dataIndex: 'supplierName', render: (value) => value || <Tag color="red">{t('Find supplier from OrderDetails')}</Tag> },
  { title: t('Lead time'), dataIndex: 'leadTimeDays', render: (value, row) => <Space size={4}><span>{number(value)} {t('days')}</span><Tag color={colorForFreshness(row.leadTimeFreshness)}>{t(row.leadTimeFreshness || 'unknown')}</Tag></Space> },
  { title: t('OOS date'), dataIndex: 'estimatedOosDate' },
  { title: t('Money at risk'), dataIndex: 'estimatedProfitRisk', render: money },
];
const supplierColumns = [
  { title: t('Supplier / next action'), dataIndex: 'supplierName', render: (value) => value === 'Find supplier from OrderDetails' ? <Tag color="red">{t(value)}</Tag> : (value || '—') },
  { title: t('Urgent'), dataIndex: 'urgentCount' },
  { title: t('A'), dataIndex: 'tierA' },
  { title: t('B'), dataIndex: 'tierB' },
  { title: t('C'), dataIndex: 'tierC' },
  { title: t('Money at risk'), dataIndex: 'estimatedProfitRisk', render: money },
];
const productColumns = [
  { title: t('Tier'), dataIndex: 'tier', render: (value) => <Tag color={colorForTier(value)}>{value || '—'}</Tag> },
  { title: t('ASIN'), dataIndex: 'asin' },
  { title: t('Supplier'), dataIndex: 'supplierName', render: (value) => value || <Tag color="red">{t('Find supplier')}</Tag> },
  { title: t('Lead'), dataIndex: 'leadTimeDays', render: (value, row) => <Space size={4}><span>{number(value)} {t('days')}</span><Tag color={colorForFreshness(row.leadTimeFreshness)}>{t(row.leadTimeFreshness || 'unknown')}</Tag></Space> },
  { title: t('OOS date'), dataIndex: 'estimatedOosDate' },
  { title: t('Money at risk'), dataIndex: 'estimatedProfitRisk', render: money },
];
ctx.render(
  <Space direction="vertical" size="large" style={{ width: '100%' }}>
    <Alert
      type="info"
      showIcon
      message={t('Digital digest preview restored')}
      description={t('These are the same operator digest panels as before. The normalized NocoBase tables underneath remain available so AI employees can inspect records through Flow surface context.')}
    />
    <Row gutter={[16, 16]}>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('Overdue')} value={digest.summary.overdue || 0} valueStyle={{ color: '#cf1322' }} /></Card></Col>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('Order today')} value={digest.summary.orderToday || 0} valueStyle={{ color: '#d4380d' }} /></Card></Col>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('Order soon')} value={digest.summary.orderSoon || 0} valueStyle={{ color: '#fa8c16' }} /></Card></Col>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('At risk')} value={digest.summary.atRisk || 0} /></Card></Col>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('Lead-time issues')} value={digest.summary.staleOrMissingLeadTime || 0} valueStyle={{ color: '#faad14' }} /></Card></Col>
      <Col xs={24} sm={12} lg={4}><Card><Statistic title={t('Suppliers')} value={digest.summary.suppliersToContact || 0} /></Card></Col>
    </Row>
    <Card title={t('Daily digest preview')} extra={<Typography.Text type="secondary">{t('Bounded to urgent action items so operators are not overloaded.')}</Typography.Text>}>
      <Space direction="vertical" size="large" style={{ width: '100%' }}>
        <div>
          <Typography.Title level={5}>{t('Order now')}</Typography.Title>
          <Typography.Paragraph type="secondary">{t('Products that should be ordered now or checked against already-placed supplier orders.')}</Typography.Paragraph>
          <Table size="small" rowKey={(row) => row.planningProductId || row.naturalKey || row.asin} dataSource={digest.sections.orderNow} pagination={false} columns={orderColumns} />
        </div>
        <Row gutter={[16, 16]}>
          <Col xs={24} lg={10}>
            <Typography.Title level={5}>{t('Supplier contact priority')}</Typography.Title>
            <Typography.Paragraph type="secondary">{t('Urgent rows grouped by supplier, including supplier recovery from OrderDetails where needed.')}</Typography.Paragraph>
            <Table size="small" rowKey={(row) => row.supplierName || row.supplierId || 'missing'} dataSource={digest.sections.suppliersToContactFirst} pagination={false} columns={supplierColumns} />
          </Col>
          <Col xs={24} lg={14}>
            <Typography.Title level={5}>{t('Products needing supplier action')}</Typography.Title>
            <Typography.Paragraph type="secondary">{t('Product-level list across tiers A, B, and C for supplier, lead-time, order timing, and OOS risk review.')}</Typography.Paragraph>
            <Table size="small" rowKey={(row) => row.planningProductId || row.naturalKey || row.asin} dataSource={digest.sections.supplierActionItems} pagination={false} columns={productColumns} />
          </Col>
        </Row>
      </Space>
    </Card>
  </Space>,
);
